mapper.select:
/* adm-system-excelhistory-sql-oracle.xml - selectExcelHistory */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT JOB.JOBID , JOB.INSERTURKEY AS URKEY , UR.URNM , JOB.MEKEY , MUDT.DISPLAYMSG AS MENM , JOB.SEARCHCOND , JOB.STATUS , JOB.DOWNLOADYN , JOB.ERRMSG , JOB.INSERTDATE , JOB.FILENM FROM TADMIN_INFO_EXCEL_JOB JOB INNER JOIN TADMIN_MST_UR UR ON UR.URKEY = JOB.INSERTURKEY AND UR.DELYN = 'N' INNER JOIN TADMIN_MST_ME ME ON ME.MEKEY = JOB.MEKEY AND ME.DELYN = 'N' INNER JOIN TADMIN_MST_MULAAPMSG_DT MUDT ON MUDT.MULAAPMSGHDKEY = ME.MENM AND MUDT.MSGTYPE = 'MENU' AND MUDT.LAKEY = #{slakey} WHERE 1 = 1 AND JOB.INSERTURKEY = #{surkey}
AND #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY INSERTDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.update:
/* adm-system-excelhistory-sql-oracle.xml - updateDownloadSuccess */
UPDATE TADMIN_INFO_EXCEL_JOB
   SET DOWNLOADYN  = 'Y'
	 , UPDATEDATE  = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE JOBID = #{jobid}
